parameters.jsCode:
const formData = $input.all();

let results = [];
const CHARS_PER_LINE = 60;
const MAX_ROWS_PER_PAGE = 35;

// Helper function to format numbers with commas and 2 decimals
// ✅ UPDATED: Returns a blank string for 0 values
function formatNumber(num) {
  if (num === null || num === undefined || isNaN(num) || num === 0) return '';
  return parseFloat(num).toLocaleString('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

// Get copies
const copies = parseInt(formData[0]?.json['Copies']) || 1;

// CAPTURE additionalCurrency from the form input
const additionalCurrency = formData[0]?.json['additionalCurrency'] || formData[0]?.json['additionalCurrencies'] || '';
console.log('🔍 Code60 - Received additionalCurrency:', additionalCurrency);

// ✅ CAPTURE ConversionRate from input
const conversionRate = formData[0]?.json['ConversionRate'] || null;
console.log('💱 ConversionRate from input:', conversionRate);

// Parse which currencies user wants
const selectedCurrencies = [];
if (additionalCurrency) {
  const currencyString = additionalCurrency.toString().toUpperCase();
  const currencies = currencyString.split(',').map(c => c.trim()).filter(c => c);
  currencies.forEach(currency => {
    if (currency === 'USD' || currency === 'EUR' || currency === 'AED') {
      selectedCurrencies.push(currency);
    }
  });
}

console.log('✅ Selected currencies for conversion:', selectedCurrencies);

// PROCESS ALL ITEMS (not just first one)
for (let itemIndex = 0; itemIndex < formData.length; itemIndex++) {
  // ✅ UPDATED: Extract Tax Code and Tax Name from input
  const taxCode = formData[itemIndex].json['Tax Code'] || '';
  const taxName = formData[itemIndex].json['Tax Name'] || '';

  const qty = formData[itemIndex].json.QTY;
  const unitRate = formData[itemIndex].json['Unit Rate'];
  const amount = formData[itemIndex].json.Amount;
  const vatPercent = formData[itemIndex].json['VAT%'];
  const vatValue = formData[itemIndex].json['VAT Value'];
  const totalAmount = formData[itemIndex].json['Total Amount'];
  const description = formData[itemIndex].json.Description || '';

  // ✅ CHECK IF THIS IS A DESCRIPTION-ONLY ROW (Note/Header row)
  const isDescriptionOnly = (
    !qty && 
    !unitRate && 
    !amount && 
    !vatValue && 
    !totalAmount &&
    description.trim() !== ''
  );

  console.log(`📝 Item ${itemIndex + 1}: ${isDescriptionOnly ? 'DESCRIPTION ONLY' : 'DATA ROW'}`);

  const currentItem = {
    qty: qty || 0,
    description: description,
    unitRate: parseFloat(unitRate) || 0,
    amount: parseFloat(amount) || 0,
    vatPercent: vatPercent,
    vatValue: parseFloat(vatValue) || 0,
    totalAmount: parseFloat(totalAmount) || 0,
    taxCode: taxCode,
    taxName: taxName,
    isDescriptionOnly: isDescriptionOnly  // ✅ NEW FLAG
  };

  // Handle vatPercent formatting based on input
  if (currentItem.vatPercent === null || currentItem.vatPercent === undefined || currentItem.vatPercent === '') {
    currentItem.vatPercent = '';
  } else {
    const vatStr = currentItem.vatPercent.toString();
    if (!vatStr.includes('%')) {
      currentItem.vatPercent = `${vatStr}%`;
    }
  }

  // Process copies for THIS item
  for (let copy = 0; copy < copies; copy++) {
    const description = currentItem.description;

    if (description.length <= CHARS_PER_LINE) {
      // Short description - single row
      // ✅ IF DESCRIPTION-ONLY: Show only description, all other fields blank
      if (currentItem.isDescriptionOnly) {
        results.push({
          qty: '',
          description: description,
          unitRate: '',
          amount: '',
          vatPercent: '',
          vatValue: '',
          totalAmount: '',
          taxCode: '',
          taxName: '',
          isDataRow: false,  // ✅ Not a data row (won't count in totals)
          isDescriptionOnly: true
        });
      } else {
        // Normal data row
        results.push({
          qty: currentItem.qty,
          description: description,
          unitRate: formatNumber(currentItem.unitRate),
          amount: formatNumber(currentItem.amount),
          vatPercent: currentItem.vatPercent,
          vatValue: formatNumber(currentItem.vatValue),
          totalAmount: formatNumber(currentItem.totalAmount),
          taxCode: currentItem.taxCode,
          taxName: currentItem.taxName,
          isDataRow: true,
          isDescriptionOnly: false
        });
      }
    } else {
      // Long description - split into multiple rows
      const descriptionParts = [];
      let remainingText = description;

      while (remainingText.length > 0) {
        if (remainingText.length <= CHARS_PER_LINE) {
          descriptionParts.push(remainingText);
          break;
        } else {
          let cutPoint = CHARS_PER_LINE;
          while (cutPoint > 0 && remainingText[cutPoint] !== ' ') {
            cutPoint--;
          }
          if (cutPoint === 0) cutPoint = CHARS_PER_LINE;
          descriptionParts.push(remainingText.substring(0, cutPoint).trim());
          remainingText = remainingText.substring(cutPoint).trim();
        }
      }

      // Create rows for each part
      for (let j = 0; j < descriptionParts.length; j++) {
        if (j === 0) {
          // First row: all data + first part of description
          // ✅ IF DESCRIPTION-ONLY: Only show description
          if (currentItem.isDescriptionOnly) {
            results.push({
              qty: '',
              description: descriptionParts[j],
              unitRate: '',
              amount: '',
              vatPercent: '',
              vatValue: '',
              totalAmount: '',
              taxCode: '',
              taxName: '',
              isDataRow: false,
              isDescriptionOnly: true
            });
          } else {
            results.push({
              qty: currentItem.qty,
              description: descriptionParts[j],
              unitRate: formatNumber(currentItem.unitRate),
              amount: formatNumber(currentItem.amount),
              vatPercent: currentItem.vatPercent,
              vatValue: formatNumber(currentItem.vatValue),
              totalAmount: formatNumber(currentItem.totalAmount),
              taxCode: currentItem.taxCode,
              taxName: currentItem.taxName,
              isDataRow: true,
              isDescriptionOnly: false
            });
          }
        } else {
          // Continuation rows: only description, everything else blank
          results.push({
            qty: '',
            description: descriptionParts[j],
            unitRate: '',
            amount: '',
            vatPercent: '',
            vatValue: '',
            totalAmount: '',
            taxCode: '',
            taxName: '',
            isDataRow: false,
            isDescriptionOnly: currentItem.isDescriptionOnly
          });
        }
      }
    }
  }
}

console.log(`📊 Total rows created: ${results.length}`);
console.log(`   Data rows: ${results.filter(r => r.isDataRow).length}`);
console.log(`   Description-only rows: ${results.filter(r => r.isDescriptionOnly).length}`);

// Page break logic
function calculatePageBreaks(items, rowsPerPage) {
  const pages = [];
  let currentPage = [];
  let currentPageRows = 0;

  for (let item of items) {
    if (currentPageRows > 0 && currentPageRows + 1 > rowsPerPage) {
      pages.push(currentPage);
      currentPage = [];
      currentPageRows = 0;
    }
    currentPage.push(item);
    currentPageRows += 1;
  }

  if (currentPage.length > 0) {
    pages.push(currentPage);
  }

  return pages;
}

// Calculate subtotals for a given page
function calculatePageSubtotals(pageItems) {
  let amount = 0;
  let vat = 0;
  let total = 0;

  for (const item of pageItems) {
    if (item.isDataRow) {
      amount += parseFloat(item.amount.replace(/,/g, '') || 0);
      vat += parseFloat(item.vatValue.replace(/,/g, '') || 0);
      total += parseFloat(item.totalAmount.replace(/,/g, '') || 0);
    }
  }

  return {
    pageAmount: formatNumber(amount),
    pageVAT: formatNumber(vat),
    pageTotal: formatNumber(total)
  };
}

// Create page mapping + inject subtotals
function createPageMapping(pageItems, startQtyNumber) {
  const mapping = {};

  for (let i = 0; i < MAX_ROWS_PER_PAGE; i++) {
    const qtyNum = startQtyNumber + i;
    const item = pageItems[i];

    if (item) {
      mapping[`qty${qtyNum}`] = item.qty;
      mapping[`description${qtyNum}`] = item.description;
      mapping[`unitrate${qtyNum}`] = item.unitRate;
      mapping[`amount${qtyNum}`] = item.amount;
      mapping[`vat%${qtyNum}`] = item.vatPercent;
      mapping[`vatvalue${qtyNum}`] = item.vatValue;
      mapping[`totalamountvalue${qtyNum}`] = item.totalAmount;
    } else {
      mapping[`qty${qtyNum}`] = '';
      mapping[`description${qtyNum}`] = '';
      mapping[`unitrate${qtyNum}`] = '';
      mapping[`amount${qtyNum}`] = '';
      mapping[`vat%${qtyNum}`] = '';
      mapping[`vatvalue${qtyNum}`] = '';
      mapping[`totalamountvalue${qtyNum}`] = '';
    }
  }

  const subtotals = calculatePageSubtotals(pageItems);
  mapping.pageSubtotalAmount = subtotals.pageAmount;
  mapping.pageSubtotalVAT = subtotals.pageVAT;
  mapping.pageSubtotalTotal = subtotals.pageTotal;

  return mapping;
}

// Calculate pages
const pageBreaks = calculatePageBreaks(results, MAX_ROWS_PER_PAGE);
const pagesNeeded = Math.min(pageBreaks.length, 6);

const page1Data = pageBreaks[0] ? createPageMapping(pageBreaks[0], 1) : {};
const page2Data = pageBreaks[1] ? createPageMapping(pageBreaks[1], 36) : {};
const page3Data = pageBreaks[2] ? createPageMapping(pageBreaks[2], 71) : {};
const page4Data = pageBreaks[3] ? createPageMapping(pageBreaks[3], 106) : {};
const page5Data = pageBreaks[4] ? createPageMapping(pageBreaks[4], 141) : {};
const page6Data = pageBreaks[5] ? createPageMapping(pageBreaks[5], 176) : {};

// CALCULATE GRAND TOTALS ACROSS ALL PAGES
let grandTotalAmount = 0;
let grandTotalVAT = 0;
let grandTotalFinal = 0;

pageBreaks.forEach(page => {
  const subtotals = calculatePageSubtotals(page);
  grandTotalAmount += parseFloat(subtotals.pageAmount.replace(/,/g, '') || 0);
  grandTotalVAT += parseFloat(subtotals.pageVAT.replace(/,/g, '') || 0);
  grandTotalFinal += parseFloat(subtotals.pageTotal.replace(/,/g, '') || 0);
});

// Format grand totals
const formattedGrandTotalAmount = formatNumber(grandTotalAmount);
const formattedGrandTotalVAT = formatNumber(grandTotalVAT);
const formattedGrandTotalFinal = formatNumber(grandTotalFinal);

console.log('📊 Grand Totals:');
console.log('   Amount:', formattedGrandTotalAmount);
console.log('   VAT:', formattedGrandTotalVAT);
console.log('   Final:', formattedGrandTotalFinal);

// Grand totals (per data rows only - excludes description-only rows)
const dataRows = results.filter(row => row.isDataRow);

// SUM ALL AMOUNTS (taxable 5%, 0%, non-taxable)
let totalAmount = 0;
let totalVAT = 0;

dataRows.forEach(item => {
  totalAmount += parseFloat(item.amount.replace(/,/g, '') || 0);
  totalVAT += parseFloat(item.vatValue.replace(/,/g, '') || 0);
});

// SUM OF ALL PER-PAGE TOTALS
let sumOfPageTotals = 0;
pageBreaks.forEach(page => {
  const subtotals = calculatePageSubtotals(page);
  sumOfPageTotals += parseFloat(subtotals.pageTotal.replace(/,/g, '') || 0);
});

// Format totals
totalAmount = formatNumber(totalAmount);
totalVAT = formatNumber(totalVAT);
sumOfPageTotals = formatNumber(sumOfPageTotals);

// ✅ UPDATED VAT BREAKDOWN - Uses Tax Name to categorize properly
let taxableAmount5Percent = 0;
let taxableAmount0Percent = 0;
let nonTaxableAmount = 0;
let vat5PercentAmount = 0;
let vat0PercentAmount = 0;

dataRows.forEach(item => {
  const amount = parseFloat(item.amount.replace(/,/g, '') || 0);
  const vatValue = parseFloat(item.vatValue.replace(/,/g, '') || 0);
  const taxName = item.taxName || '';

  // Get VAT percent for logging
  const vatPercentStr = item.vatPercent?.toString().replace('%', '') || '0';
  const vatPercent = parseFloat(vatPercentStr);

  // Categorize based on Tax Name (matching first code's logic)
  if (taxName === 'Taxable Amount @ 5%' || vatPercent === 5) {
    taxableAmount5Percent += amount;
    vat5PercentAmount += vatValue;
  } else if (taxName === 'Taxable Amount @ 0%') {
    taxableAmount0Percent += amount;
    vat0PercentAmount += vatValue;
  } else if (taxName === 'Non Taxable Amount') {
    nonTaxableAmount += amount;
  } else {
    // Fallback: Use VAT% if Tax Name not available
    if (vatPercent === 5) {
      taxableAmount5Percent += amount;
      vat5PercentAmount += vatValue;
    } else if (vatPercent === 0) {
      taxableAmount0Percent += amount;
      vat0PercentAmount += vatValue;
    } else {
      nonTaxableAmount += amount;
    }
  }
});

// Invoice summary
const invoiceSummary = {
  taxableAmount5Percent: formatNumber(taxableAmount5Percent),
  taxableAmount0Percent: formatNumber(taxableAmount0Percent),
  nonTaxableAmount: formatNumber(nonTaxableAmount),
  vat5Percent: formatNumber(vat5PercentAmount),
  vat0Percent: formatNumber(vat0PercentAmount),
  totalAmountAED: sumOfPageTotals
};

console.log('📊 VAT Breakdown Summary:');
console.log(`   Taxable Amount @ 5%: ${invoiceSummary.taxableAmount5Percent}`);
console.log(`   5% VAT: ${invoiceSummary.vat5Percent}`);
console.log(`   Taxable Amount @ 0%: ${invoiceSummary.taxableAmount0Percent}`);
console.log(`   Non Taxable Amount: ${invoiceSummary.nonTaxableAmount}`);
console.log(`   Total Amount (AED): ${invoiceSummary.totalAmountAED}`);

// Get currency used from form
const currencyused = formData[0]?.json['currencyused'] || 'AED';

// ✅ EXTRACT Currency and HomeBalance from input
const currency = formData[0]?.json['Currency'] || 'AED';
const homeBalanceAED = formData[0]?.json['HomeBalance (AED)'] || null;

console.log('💱 Currency:', currency);
if (homeBalanceAED !== null) {
  console.log('🏠 HomeBalance (AED):', homeBalanceAED);
}

// Determine which HTTP nodes need to be called
const needUSDConversion = selectedCurrencies.includes('USD') && currencyused !== 'USD';
const needEURConversion = selectedCurrencies.includes('EUR') && currencyused !== 'EUR';

console.log('📤 Code Output - additionalCurrency:', additionalCurrency);
console.log('🔄 Need USD conversion:', needUSDConversion);
console.log('🔄 Need EUR conversion:', needEURConversion);


// ✅ UPDATED & REFACTORED: BUILD PAGE OBJECTS WITH CORRECT SUBTOTALS AND GRAND TOTALS
const allPageData = [page1Data, page2Data, page3Data, page4Data, page5Data, page6Data];
const finalPages = {};

for (let i = 0; i < pagesNeeded; i++) {
    const pageNum = i + 1;
    const currentPageData = allPageData[i];
    const isLastPage = (pageNum === pagesNeeded);

    finalPages[`page${pageNum}`] = {
        ...currentPageData,
        subtotal: {
            amount: currentPageData.pageSubtotalAmount || '',
            vat: currentPageData.pageSubtotalVAT || '',
            total: currentPageData.pageSubtotalTotal || ''
        },
        grandTotal: {
            amount: isLastPage ? formattedGrandTotalAmount : '',
            vat: isLastPage ? formattedGrandTotalVAT : '',
            total: isLastPage ? formattedGrandTotalFinal : ''
        },
        showVATBreakdown: isLastPage
    };
}

const page1 = finalPages.page1 || {};
const page2 = finalPages.page2 || {};
const page3 = finalPages.page3 || {};
const page4 = finalPages.page4 || {};
const page5 = finalPages.page5 || {};
const page6 = finalPages.page6 || {};


return [{
  json: {
    // PASS THROUGH additionalCurrency and conversion flags
    additionalCurrency: additionalCurrency,
    selectedCurrencies: selectedCurrencies,
    needUSDConversion: needUSDConversion,
    needEURConversion: needEURConversion,
    currencyused: currencyused,

    // ✅ PASS THROUGH ConversionRate
    ConversionRate: conversionRate,

    // ✅ CURRENCY AND HOMEBALANCE
    Currency: currency,
    ...(homeBalanceAED !== null && { 'HomeBalance (AED)': homeBalanceAED }),

    items: results,

    // TOTALS - Multiple formats for compatibility
    totalAmount: totalAmount,
    totalVAT: totalVAT,
    grandTotal: sumOfPageTotals,

    totals: { 
      totalAmount: totalAmount, 
      totalVAT: totalVAT, 
      grandTotal: sumOfPageTotals,
      allgrandtotalamount: formattedGrandTotalAmount,
      allgrandtotalvat: formattedGrandTotalVAT,
      allgrandtotaltotal: formattedGrandTotalFinal
    },

    allgrandtotalamount: formattedGrandTotalAmount,
    allgrandtotalvat: formattedGrandTotalVAT,
    allgrandtotaltotal: formattedGrandTotalFinal,

    grandTotals: {
      amount: formattedGrandTotalAmount,
      vat: formattedGrandTotalVAT,
      total: formattedGrandTotalFinal
    },

    grandTotalAmount: formattedGrandTotalAmount,
    grandTotalVAT: formattedGrandTotalVAT,
    grandTotalFinal: formattedGrandTotalFinal,

    itemCount: dataRows.length,
    totalRowsNeeded: results.length,
    templatePageNumber: pagesNeeded,

    // ✅ UPDATED VAT BREAKDOWN - Shows on last page only
    invoiceSummary,
    vatBreakdown: {
      taxableAmount5Percent: invoiceSummary.taxableAmount5Percent,
      taxableAmount0Percent: invoiceSummary.taxableAmount0Percent,
      nonTaxableAmount: invoiceSummary.nonTaxableAmount,
      vat5Percent: invoiceSummary.vat5Percent,
      vat0Percent: invoiceSummary.vat0Percent,
      totalAmountAED: invoiceSummary.totalAmountAED
    },
    "5%value": invoiceSummary.taxableAmount5Percent,
    "0%value": invoiceSummary.taxableAmount0Percent,
    "nontaxablevalue": invoiceSummary.nonTaxableAmount,
    "5%vatvalue": invoiceSummary.vat5Percent,
    "totalamountfinal": invoiceSummary.totalAmountAED,

    allPagesGrandTotal: formattedGrandTotalFinal,

    // ✅ PAGE DATA WITH CORRECT SUBTOTALS AND GRAND TOTALS
    page1: page1,
    page2: page2,
    page3: page3,
    page4: page4,
    page5: page5,
    page6: page6,

    // KEEP OLD FORMAT FOR BACKWARD COMPATIBILITY
    page1Data,
    page2Data,
    page3Data,
    page4Data,
    page5Data,
    page6Data,

    customerInfo: {
      name: formData[0]?.json['Name'] || 'Sample Customer',
      address: formData[0]?.json['Address'] || 'Sample Address',
      emirates: formData[0]?.json['Emirates'] || 'Dubai',
      invoiceNo: formData[0]?.json['Invoice No'] || 'INV-001',
      docNumber: formData[0]?.json['DocNumber'] || formData[0]?.json['Invoice No'] || 'INV-001',
      DocId: formData[0]?.json['INV-Id'] || formData[0]?.json['Invoice No'] || 'INV-001',
      placeOfSupply: formData[0]?.json['Place of Supply'] || 'UAE',
      trnNo: formData[0]?.json['TRN No'] || '',
      "Id": formData[0]?.json['Id'] || ''
    },
    yachtName: formData[0]?.json['YachtName'] || formData[0]?.json['yachtName'] || '',
    yachtPO: formData[0]?.json['YachtPO'] || formData[0]?.json['yachtPO'] || '',
    bankDetail: formData[0]?.json['Bank Detail'] || '',
    invoiceDate: formData[0]?.json['Date'] || new Date().toLocaleDateString('en-GB'),

  }
}];

// ✅ Fixed QuickBooks Estimates/Quotations Data Transformation with Currency Support
// ✅ NOW EXTRACTS ALL ITEMS including description-only rows
// ✅ UPDATED: Removed tabs (\t), newlines (\n), and extra spaces from Description fields

// ✅ MODIFIED: Direct extraction from specific node
const invoice = $('Get Pro-Forma1').first().json.Invoice || {};

// Invoice-level values
const docNumber = invoice.DocNumber || invoice.Id || `QB-${Date.now()}`;
const customer = invoice.CustomerRef || {};
const billAddr = invoice.BillAddr || {};
const shipAddr = invoice.ShipAddr || {};
const taxDetail = invoice.TxnTaxDetail || {};

// ✅ ADDED: Home Total Amount
const homeTotalAmt = invoice.HomeTotalAmt ?? null;

// Currency detection from CurrencyRef
const currencyCode = invoice.CurrencyRef?.value || 'AED';
const isUSD = currencyCode === 'USD';
const homeBalance = isUSD ? (invoice.HomeBalance || 0) : null;

// ✅ Extract CustomField data from the SAME invoice object
let yachtName = '';
let yachtPO = '';
let currencyType = '1'; // Default AED
let conversionRate = 1;
let displayCurrency = 'AED';

// ✅ NEW: Bank Detail
let bankDetailType = '1'; // Default AED Bank
let bankDetail = 'AED';

const customFields = invoice.CustomField || [];

// ✅ Parse CustomField array
customFields.forEach(field => {
    if (field.Name === 'Yacht.Name') {
        yachtName = field.StringValue || '';
    } 
    else if (field.Name === 'Yacht.PO') {
        yachtPO = field.StringValue || '';
    } 
    else if (field.Name === 'Currency') {
        currencyType = field.StringValue || '1';
    } 
    else if (field.Name === 'Conversion Rate') {
        conversionRate = field.NumberValue || 1;
    }
    // ✅ Bank Detail extraction
    else if (field.Name === 'Bank Detail') {
        bankDetailType = field.StringValue || '1';
    }
});

// ✅ Currency Logic Mapping
const currencyMap = {
    '1': 'AED',
    '2': 'USD',
    '3': 'EUR',
    '4': 'AED TO USD',
    '5': 'AED TO EUR'
};

displayCurrency = currencyMap[currencyType] || 'AED';

// ✅ Bank Detail Mapping
const bankDetailMap = {
    '1': 'AED',
    '2': 'USD',
    '3': 'EURO'
};

bankDetail = bankDetailMap[bankDetailType] || 'AED';

// Tax code mapping
const taxCodeMap = {
  '19': { id: 21, name: 'Taxable Amount @ 5%', rate: 5 },
  '17': { id: 22, name: 'Taxable Amount @ 0%', rate: 0 },
  '18': { id: 24, name: 'Non Taxable Amount', rate: '' },
  '21': { id: 21, name: 'Taxable Amount @ 5%', rate: 5 },
  '22': { id: 22, name: 'Taxable Amount @ 0%', rate: 0 },
  '24': { id: 24, name: 'Non Taxable Amount', rate: 0 }
};

// ✅ Extract ALL line items
const allLines = invoice.Line || [];

// ✅ Process SalesItemLineDetail AND DescriptionOnly
const processableLines = allLines.filter(line => 
    line.DetailType === 'SalesItemLineDetail' || 
    line.DetailType === 'DescriptionOnly'
);

if (processableLines.length === 0) {
    return [];
}

const processedItems = [];

function parseQty(raw) {
    if (raw === undefined || raw === null || raw === '') return '';
    const n = Number(raw);
    return isNaN(n) ? '' : n;
}

// ✅ Clean description helper
function cleanDescription(desc) {
    if (!desc) return '';
    return desc.replace(/[\t\n\r]+/g, ' ').replace(/\s+/g, ' ').trim();
}

processableLines.forEach((line, index) => {
    const lineType = line.DetailType;
    const isDescriptionOnly = (lineType === 'DescriptionOnly');

    const iso = invoice.MetaData?.CreateTime || new Date().toISOString();
    const d = new Date(iso);
    const formattedDate = `${String(d.getDate()).padStart(2, '0')}/${String(d.getMonth() + 1).padStart(2, '0')}/${d.getFullYear()}`;

    if (isDescriptionOnly) {
        const description = cleanDescription(line.Description);

        processedItems.push({
            json: {
                'QTY': '',
                'Item Name': '',
                'Description': description,
                'Unit Rate': '',
                'Amount': '',
                'VAT%': '',
                'VAT Value': '',
                'Total Amount': '',
                'Tax Code': '',
                'Tax Name': '',
                'Name': customer.name || 'Unknown Customer',
                'YachtName': yachtName,
                'YachtPO': yachtPO,
                'Address': `${billAddr.Line1 || ''} ${billAddr.Line2 || ''} ${billAddr.Line3 || ''} ${billAddr.City || ''}`.trim(),
                'Emirates': billAddr.City || 'Dubai',
                'Invoice No': docNumber,
                'Date': formattedDate,
                'DocNumber': docNumber,
                'Id': invoice.Id || docNumber,
                'Place of Supply': shipAddr.Country || 'UAE',
                'Copies': 1,
                'EST-Id': invoice.Id || '',
                'Currency': displayCurrency,
                'ConversionRate': conversionRate,
                'Bank Detail': bankDetail
            }
        });

    } else {
        const salesDetail = line.SalesItemLineDetail || {};
        const itemRef = salesDetail.ItemRef || {};
        const taxCodeRef = salesDetail.TaxCodeRef || {};

        const qty = parseQty(line.Qty ?? salesDetail.Qty);
        const unitRate = Number(salesDetail.UnitPrice || 0);
        const amount = Number(line.Amount ?? (qty * unitRate) ?? 0);

        const taxCodeValue = taxCodeRef.value || '19';
