const text = $input.first().json.text;

// Normalize text lines
const lines = text
  .split('\n')
  .map(l => l.trim())
  .filter(Boolean);

// Locate table header
const start = lines.findIndex(l =>
  l.includes('QTY') && l.includes('DESCRIPTION')
);

if (start === -1) {
  throw new Error('Table header not found');
}

// Collect table content
const table = [];
for (let i = start + 1; i < lines.length; i++) {
  if (lines[i].includes('Total Amount')) break;
  table.push(lines[i]);
}

// ---------- COLLECT QTY ----------
const qty = [];
let index = 0;
while (/^\d+$/.test(table[index])) {
  qty.push(Number(table[index]));
  index++;
}

const rowCount = qty.length;

// ---------- COLLECT DESCRIPTION (MERGE LINES) ----------
const desc = [];
let current = '';

while (desc.length < rowCount && index < table.length) {
  const line = table[index];

  // Stop when numbers start
  if (/^\d+\.\d{2}$/.test(line)) break;

  current += (current ? ' ' : '') + line;

  // Push only when we have enough descriptions
  if (desc.length < rowCount - 1) {
    desc.push(current);
    current = '';
  }

  index++;
}

// Last description absorbs remaining text
if (desc.length < rowCount && current) {
  desc.push(current);
}

// ---------- COLLECT NUMERIC COLUMNS ----------
const collectNumbers = () => {
  const arr = [];
  for (let i = 0; i < rowCount; i++) {
    arr.push(Number(table[index++]));
  }
  return arr;
};

const unitRate = collectNumbers();
const amount = collectNumbers();

const vatPercent = [];
for (let i = 0; i < rowCount; i++) {
  vatPercent.push(Number(table[index++].replace('%', '')));
}

const vat = collectNumbers();
const total = collectNumbers();

// ---------- BUILD ROWS ----------
const rows = Array.from({ length: rowCount }, (_, i) => ({
  qty: qty[i],
  description: desc[i],
  unitRate: unitRate[i],
  amount: amount[i],
  vatPercent: vatPercent[i],
  vat: vat[i],
  total: total[i],
}));

return rows.map(r => ({ json: r }));

